def top_k_frequent(nums, k):
    counts = {}
    for x in nums:
        counts[x] = counts.get(x, 0) + 1
    buckets = [[] for _ in range(len(nums) + 1)]
    for val, c in counts.items():
        buckets[c].append(val)
    result = []
    for c in range(len(buckets) - 1, 0, -1):
        for val in buckets[c]:
            result.append(val)
            if len(result) == k:
                return result
    return result
